/* ── Scene, Camera, Renderer ── */

const scene = new THREE.Scene();
scene.background = new THREE.Color(CONFIG.renderer.backgroundColor);

const frustum = CONFIG.camera.frustum;
let aspect = window.innerWidth / window.innerHeight;
const cam = new THREE.OrthographicCamera(
  -frustum * aspect,
  frustum * aspect,
  frustum,
  -frustum,
  CONFIG.camera.near,
  CONFIG.camera.far
);
cam.position.set(...CONFIG.camera.startPosition);
cam.lookAt(0, 0, 0);
cam.zoom = CONFIG.camera.zoom.initial;
cam.updateProjectionMatrix();

const renderer = new THREE.WebGLRenderer({ antialias: CONFIG.renderer.antialias });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, CONFIG.renderer.pixelRatioMax));
renderer.shadowMap.enabled = CONFIG.renderer.shadows.enabled;
renderer.shadowMap.type = CONFIG.renderer.shadows.type;
document.getElementById('wrap').appendChild(renderer.domElement);

const GAME = {
  scene,
  camera: cam,
  renderer,
  occludables: [],
  occlusionMeshes: [],
};

function registerOccludable(group) {
  group.userData.occludable = true;
  group.userData.occlusionMeshes = [];

  group.traverse(child => {
    if (!child.isMesh) return;
    child.userData.occludableGroup = group;
    group.userData.occlusionMeshes.push(child);
    GAME.occlusionMeshes.push(child);
  });

  GAME.occludables.push(group);
}

/* ── Lighting ── */

const ambLight = new THREE.AmbientLight(
  CONFIG.renderer.ambient.color,
  CONFIG.renderer.ambient.intensity
);
scene.add(ambLight);

const dirLight = new THREE.DirectionalLight(
  CONFIG.renderer.directional.color,
  CONFIG.renderer.directional.intensity
);
dirLight.position.set(...CONFIG.renderer.directional.startPosition);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(CONFIG.renderer.shadows.mapSize, CONFIG.renderer.shadows.mapSize);
dirLight.shadow.camera.left = -CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.right = CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.top = CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.bottom = -CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.near = CONFIG.renderer.shadows.near;
dirLight.shadow.camera.far = CONFIG.renderer.shadows.far;
scene.add(dirLight);


/* ── Input ── */

const keys = {};
document.addEventListener('keydown', e => {
  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
  keys[e.code] = true;
  if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.code)) e.preventDefault();
});
document.addEventListener('keyup', e => { keys[e.code] = false; });
document.addEventListener('contextmenu', e => e.preventDefault());

// Clear all keys when window loses focus
function clearKeys() { for (const k in keys) delete keys[k]; }
window.addEventListener('blur', clearKeys);
window.addEventListener('focus', clearKeys);
document.addEventListener('visibilitychange', () => { if (document.hidden) clearKeys(); });


/* ── World Data Generation ── */

function createSeededRandom(initialSeed) {
  let seed = initialSeed;

  return {
    setSeed(nextSeed) {
      seed = nextSeed;
    },
    next() {
      seed = (seed * 16807 + 0) % 2147483647;
      return (seed & 0x7fffffff) / 0x7fffffff;
    },
    int(min, max) {
      return min + Math.floor(this.next() * (max - min + 1));
    },
  };
}

function createWorldData() {
  const width = CONFIG.world.width;
  const height = CONFIG.world.height;
  const map = Array.from({ length: height }, () => new Array(width).fill(CONFIG.world.tiles.grass));
  const buildings = [];
  const buildingGroups = [];
  const buildingGroupMap = Array.from({ length: height }, () => new Array(width).fill(-1));
  const random = createSeededRandom(CONFIG.world.seeds.buildings);
  const roads = {
    rows: [...CONFIG.world.roadRows],
    cols: [...CONFIG.world.roadCols],
  };
  const generation = CONFIG.world.generation;
  const tiles = CONFIG.world.tiles;

  function fillRoads() {
    for (const row of roads.rows) {
      for (let c = 0; c < width; c++) {
        map[row][c] = tiles.road;
        map[row + 1][c] = tiles.road;
        if (row > 0 && map[row - 1][c] === tiles.grass) map[row - 1][c] = tiles.sidewalk;
        if (row + 2 < height && map[row + 2][c] === tiles.grass) map[row + 2][c] = tiles.sidewalk;
      }
    }

    for (const col of roads.cols) {
      for (let r = 0; r < height; r++) {
        map[r][col] = tiles.road;
        map[r][col + 1] = tiles.road;
        if (col > 0 && map[r][col - 1] === tiles.grass) map[r][col - 1] = tiles.sidewalk;
        if (col + 2 < width && map[r][col + 2] === tiles.grass) map[r][col + 2] = tiles.sidewalk;
      }
    }
  }

  function canPlace(r, c, w, d, margin) {
    for (let dr = -margin; dr < d + margin; dr++) {
      for (let dc = -margin; dc < w + margin; dc++) {
        const rr = r + dr;
        const cc = c + dc;
        if (rr < 0 || rr >= height || cc < 0 || cc >= width) return false;
        if (map[rr][cc] !== tiles.grass) return false;
      }
    }

    return true;
  }

  function placeBuilding(r, c, w, d) {
    for (let dr = 0; dr < d; dr++) {
      for (let dc = 0; dc < w; dc++) {
        map[r + dr][c + dc] = tiles.building;
      }
    }

    const building = { r, c, w, d };
    buildings.push(building);
    return building;
  }

  function addFence(br, bc, bw, bd, roadSide) {
    const pad = generation.fencePadding;
    const fTop = br - pad;
    const fBot = br + bd + pad - 1;
    const fLeft = bc - pad;
    const fRight = bc + bw + pad - 1;
    const gateC = bc + Math.floor(bw / 2);
    const gateR = br + Math.floor(bd / 2);

    for (let r = fTop; r <= fBot; r++) {
      for (let c = fLeft; c <= fRight; c++) {
        if (r < 0 || r >= height || c < 0 || c >= width) continue;
        if (map[r][c] !== tiles.grass) continue;

        const isEdge = r === fTop || r === fBot || c === fLeft || c === fRight;
        if (!isEdge) continue;

        let isGate = false;
        if (roadSide === 'bottom' && r === fBot && c === gateC) isGate = true;
        if (roadSide === 'top' && r === fTop && c === gateC) isGate = true;
        if (roadSide === 'right' && c === fRight && r === gateR) isGate = true;
        if (roadSide === 'left' && c === fLeft && r === gateR) isGate = true;

        map[r][c] = isGate ? tiles.gate : tiles.fence;
      }
    }
  }

  function placeBuildings() {
    const hBounds = [0, ...roads.rows.map(row => row - 1), height - 1];
    const vBounds = [0, ...roads.cols.map(col => col - 1), width - 1];

    for (let blockRow = 0; blockRow < hBounds.length - 1; blockRow++) {
      for (let blockCol = 0; blockCol < vBounds.length - 1; blockCol++) {
        const blockTop = hBounds[blockRow] + generation.blockInset;
        const blockBottom = hBounds[blockRow + 1] - generation.blockBottomInset;
        const blockLeft = vBounds[blockCol] + generation.blockInset;
        const blockRight = vBounds[blockCol + 1] - generation.blockBottomInset;
        const blockW = blockRight - blockLeft;
        const blockH = blockBottom - blockTop;

        if (blockW < generation.lotWidth || blockH < generation.lotDepth) continue;

        for (
          let col = blockLeft;
          col + 5 <= blockRight;
          col += generation.lotWidth + random.int(0, generation.lotJitterMax)
        ) {
          const bw = random.int(3, 5);
          const bd = random.int(3, 4);
          const br = blockTop + generation.yardSetback;
          const bc = col + random.int(0, 1);

          if (canPlace(br, bc, bw, bd, generation.yardSetback)) {
            const building = placeBuilding(br, bc, bw, bd);
            if (random.next() < generation.fenceChance) addFence(building.r, building.c, building.w, building.d, 'top');
          }
        }

        for (
          let col = blockLeft;
          col + 5 <= blockRight;
          col += generation.lotWidth + random.int(0, generation.lotJitterMax)
        ) {
          const bw = random.int(3, 5);
          const bd = random.int(3, 4);
          const br = blockBottom - generation.yardSetback - bd;
          const bc = col + random.int(0, 1);

          if (canPlace(br, bc, bw, bd, generation.yardSetback)) {
            const building = placeBuilding(br, bc, bw, bd);
            if (random.next() < generation.fenceChance) addFence(building.r, building.c, building.w, building.d, 'bottom');
          }
        }
      }
    }
  }

  function placeTrees() {
    random.setSeed(CONFIG.world.seeds.trees);

    for (let r = 1; r < height - 1; r += 2) {
      for (let c = 1; c < width - 1; c += 2) {
        if (map[r][c] !== tiles.grass) continue;
        if (random.next() >= generation.treeChance) continue;

        const tr = r + random.int(0, 1);
        const tc = c + random.int(0, 1);
        if (tr < height && tc < width && map[tr][tc] === tiles.grass) {
          map[tr][tc] = tiles.tree;
        }
      }
    }
  }

  function placeStructures() {
    random.setSeed(CONFIG.world.seeds.structures);

    for (let r = 2; r < height - 2; r += 3) {
      for (let c = 2; c < width - 2; c += 3) {
        if (map[r][c] !== tiles.grass) continue;
        if (random.next() < generation.structureChance) {
          map[r][c] = tiles.structure;
        }
      }
    }
  }

  function buildBuildingGroups() {
    let groupId = 0;

    for (let r = 0; r < height; r++) {
      for (let c = 0; c < width; c++) {
        if (map[r][c] !== tiles.building || buildingGroupMap[r][c] !== -1) continue;

        const cells = [];
        const queue = [{ r, c }];
        buildingGroupMap[r][c] = groupId;

        while (queue.length) {
          const current = queue.shift();
          cells.push(current);

          for (const [dr, dc] of [[0, 1], [0, -1], [1, 0], [-1, 0]]) {
            const nr = current.r + dr;
            const nc = current.c + dc;

            if (nr < 0 || nr >= height || nc < 0 || nc >= width) continue;
            if (map[nr][nc] !== tiles.building || buildingGroupMap[nr][nc] !== -1) continue;

            buildingGroupMap[nr][nc] = groupId;
            queue.push({ r: nr, c: nc });
          }
        }

        let minC = width;
        let maxC = 0;
        let minR = height;
        let maxR = 0;

        for (const cell of cells) {
          if (cell.c < minC) minC = cell.c;
          if (cell.c > maxC) maxC = cell.c;
          if (cell.r < minR) minR = cell.r;
          if (cell.r > maxR) maxR = cell.r;
        }

        const w = maxC - minC + 1;
        const d = maxR - minR + 1;
        const area = cells.length;
        const floors = area <= 6 ? (groupId % 3 === 0 ? 2 : 1) : (groupId % 2 === 0 ? 2 : 1);
        const floorH = 1.4 + (groupId % 3) * 0.15;

        buildingGroups.push({
          pal: CONFIG.world.buildingPalettes[groupId % CONFIG.world.buildingPalettes.length],
          h: floors * floorH,
          floors,
          floorH,
          roofType: groupId % 3,
          minC,
          maxC,
          minR,
          maxR,
          w,
          d,
          area,
          cells,
        });

        groupId++;
      }
    }
  }

  fillRoads();
  placeBuildings();
  placeTrees();
  placeStructures();
  buildBuildingGroups();

  return {
    width,
    height,
    map,
    roads,
    tiles,
    buildings,
    buildingGroups,
    buildingGroupMap,
    colliders: CONFIG.world.colliders,
  };
}

const WORLD = createWorldData();


/* ── World Helpers & Collision ── */

const MW = WORLD.width;
const MH = WORLD.height;
const MAP = WORLD.map;
const hRoads = WORLD.roads.rows;
const vRoads = WORLD.roads.cols;
const gInfo = WORLD.buildingGroups;
const COLLIDERS = WORLD.colliders;
const FENCE_COLLIDERS = [];

function worldXFromCol(col) {
  return col - MW / 2 + 0.5;
}

function worldZFromRow(row) {
  return row - MH / 2 + 0.5;
}

function isFenceTile(tile) {
  return tile === WORLD.tiles.fence || tile === WORLD.tiles.gate;
}

function addFenceCollider(cx, cz, hw, hd) {
  FENCE_COLLIDERS.push({ cx, cz, hw, hd });
}

function hitsFenceCollider(tx, ty) {
  for (const collider of FENCE_COLLIDERS) {
    if (Math.abs(tx - collider.cx) < collider.hw && Math.abs(ty - collider.cz) < collider.hd) {
      return true;
    }
  }

  return false;
}

function isSolid(tx, ty) {
  const c = Math.round(tx);
  const r = Math.round(ty);

  if (c < 0 || c >= MW || r < 0 || r >= MH) return true;
  if (hitsFenceCollider(tx, ty)) return true;

  for (const [dc, dr] of [[0, 0], [1, 0], [-1, 0], [0, 1], [0, -1]]) {
    const nc = c + dc;
    const nr = r + dr;

    if (nc < 0 || nc >= MW || nr < 0 || nr >= MH) continue;

    const collider = COLLIDERS[MAP[nr][nc]];
    if (!collider) continue;
    if (isFenceTile(MAP[nr][nc])) continue;

    const dx = tx - nc;
    const dy = ty - nr;

    if (collider.shape === 'circle') {
      if (dx * dx + dy * dy < collider.radius * collider.radius) return true;
      continue;
    }

    if (Math.abs(dx) < collider.hw && Math.abs(dy) < collider.hd) return true;
  }

  return false;
}


/* ── Terrain (instanced for performance) ── */

const GRASS = CONFIG.terrain.grassColors;
const ASPHALT = CONFIG.terrain.asphaltColors;
const SIDEWALK = CONFIG.terrain.sidewalkColors;
const TERRAIN_TILE = WORLD.tiles;

const tileGeo = new THREE.BoxGeometry(1, 0.15, 1);
const dummy = new THREE.Object3D();

const colorBuckets = {};
for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  const t = MAP[r][c];
  let col;
  let yOff = -0.075;

  if (t === TERRAIN_TILE.road) {
    col = ASPHALT[(c + r * 3) % ASPHALT.length];
    yOff = -0.09;
  } else if (t === TERRAIN_TILE.sidewalk) {
    col = SIDEWALK[(c * 5 + r * 2) % SIDEWALK.length];
    yOff = -0.04;
  } else {
    col = GRASS[(c * 3 + r * 7 + c * r) % GRASS.length];
  }

  const key = col + '|' + yOff;
  if (!colorBuckets[key]) colorBuckets[key] = { col, yOff, tiles: [] };
  colorBuckets[key].tiles.push({ c, r });
}

for (const key in colorBuckets) {
  const bucket = colorBuckets[key];
  const mat = new THREE.MeshLambertMaterial({ color: bucket.col });
  const mesh = new THREE.InstancedMesh(tileGeo, mat, bucket.tiles.length);
  mesh.receiveShadow = true;

  for (let i = 0; i < bucket.tiles.length; i++) {
    const tile = bucket.tiles[i];
    dummy.position.set(worldXFromCol(tile.c), bucket.yOff, worldZFromRow(tile.r));
    dummy.updateMatrix();
    mesh.setMatrixAt(i, dummy.matrix);
  }

  mesh.instanceMatrix.needsUpdate = true;
  scene.add(mesh);
}

/* ── Road markings (center line) ── */
const markGeo = new THREE.PlaneGeometry(0.08, 0.6);
const markMat = new THREE.MeshBasicMaterial({ color: 0xCCCC88, transparent: true, opacity: 0.6 });

for (const row of hRoads) {
  for (let c = 0; c < MW; c += 2) {
    if (MAP[row][c] !== TERRAIN_TILE.road) continue;
    const mark = new THREE.Mesh(markGeo, markMat);
    mark.rotation.x = -Math.PI / 2;
    mark.rotation.z = Math.PI / 2;
    mark.position.set(worldXFromCol(c), -0.005, worldZFromRow(row) + 0.5);
    scene.add(mark);
  }
}

for (const col of vRoads) {
  for (let r = 0; r < MH; r += 2) {
    if (MAP[r][col] !== TERRAIN_TILE.road) continue;
    const mark = new THREE.Mesh(markGeo, markMat);
    mark.rotation.x = -Math.PI / 2;
    mark.position.set(worldXFromCol(col) + 0.5, -0.005, worldZFromRow(r));
    scene.add(mark);
  }
}

/* ── Curb edges ── */
const curbMat = new THREE.MeshLambertMaterial({ color: 0x888878 });

for (const row of hRoads) {
  for (let c = 0; c < MW; c++) {
    if (MAP[row][c] !== TERRAIN_TILE.road) continue;

    if (row > 0 && MAP[row - 1][c] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(1, 0.08, 0.06), curbMat);
      curb.position.set(worldXFromCol(c), 0.0, row - MH / 2);
      scene.add(curb);
    }

    if (row + 2 < MH && MAP[row + 2][c] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(1, 0.08, 0.06), curbMat);
      curb.position.set(worldXFromCol(c), 0.0, row + 2 - MH / 2);
      scene.add(curb);
    }
  }
}

for (const col of vRoads) {
  for (let r = 0; r < MH; r++) {
    if (MAP[r][col] !== TERRAIN_TILE.road) continue;

    if (col > 0 && MAP[r][col - 1] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.08, 1), curbMat);
      curb.position.set(col - MW / 2, 0.0, worldZFromRow(r));
      scene.add(curb);
    }

    if (col + 2 < MW && MAP[r][col + 2] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.08, 1), curbMat);
      curb.position.set(col + 2 - MW / 2, 0.0, worldZFromRow(r));
      scene.add(curb);
    }
  }
}

/* ── Traffic signs — yield signs on secondary roads at intersections ── */

const signPoleMat = new THREE.MeshLambertMaterial({ color: 0x888888 });
const signPoleGeo = new THREE.CylinderGeometry(0.02, 0.02, 1.2, 6);
const signBorderMat = new THREE.MeshLambertMaterial({ color: 0xCC2222 });
const signInnerMat = new THREE.MeshLambertMaterial({ color: 0xFFFFFF });
const signBackMat = new THREE.MeshLambertMaterial({ color: 0x666666 });
const yieldOuterShape = new THREE.Shape();
yieldOuterShape.moveTo(0, -0.18);
yieldOuterShape.lineTo(0.16, 0.12);
yieldOuterShape.lineTo(-0.16, 0.12);
yieldOuterShape.lineTo(0, -0.18);

const yieldInnerShape = new THREE.Shape();
const yieldInset = 0.04;
yieldInnerShape.moveTo(0, -0.18 + yieldInset * 1.5);
yieldInnerShape.lineTo(0.16 - yieldInset, 0.12 - yieldInset);
yieldInnerShape.lineTo(-0.16 + yieldInset, 0.12 - yieldInset);
yieldInnerShape.lineTo(0, -0.18 + yieldInset * 1.5);

const signOuterGeo = new THREE.ShapeGeometry(yieldOuterShape);
const signInnerGeo = new THREE.ShapeGeometry(yieldInnerShape);

function addYieldSign(x, z, facingAngle) {
  const signGroup = new THREE.Group();

  const pole = new THREE.Mesh(signPoleGeo, signPoleMat);
  pole.position.set(x, 0.6, z);
  pole.castShadow = true;
  signGroup.add(pole);

  const signOuter = new THREE.Mesh(signOuterGeo, signBorderMat);
  signOuter.position.set(x, 1.15, z);
  signOuter.rotation.y = facingAngle;
  signGroup.add(signOuter);

  const signInner = new THREE.Mesh(signInnerGeo, signInnerMat);
  signInner.position.set(x, 1.15, z);
  signInner.rotation.y = facingAngle;
  signInner.translateZ(0.002);
  signGroup.add(signInner);

  const signBack = new THREE.Mesh(signOuterGeo, signBackMat);
  signBack.position.set(x, 1.15, z);
  signBack.rotation.y = facingAngle + Math.PI;
  signBack.translateZ(0.002);
  signGroup.add(signBack);

  scene.add(signGroup);
}

for (const row of hRoads) {
  for (const col of vRoads) {
    const hx = col - MW / 2;
    const hz = row - MH / 2;
    addYieldSign(hx + 2.8, hz - 1.2, 0);
    addYieldSign(hx - 0.8, hz + 3.2, Math.PI);
  }
}


/* ── Buildings ── */

const ROOF_COLORS = CONFIG.world.roofColors;
const SMALL_STRUCTURE_COLORS = CONFIG.world.smallStructureColors;
const BUILDING_TILE = WORLD.tiles;
const WINDOW_FRAME_MAT = new THREE.MeshLambertMaterial({ color: 0x303030, transparent: true });
const WINDOW_GLASS_MAT = new THREE.MeshBasicMaterial({ color: 0xC8D8E8, transparent: true, opacity: 0.45 });
const WINDOW_GLOW_MAT = new THREE.MeshBasicMaterial({ color: 0xffdc64, transparent: true, opacity: 0.2 });
const WINDOW_SILL_MAT = new THREE.MeshLambertMaterial({ color: 0x888880, transparent: true });
const WINDOW_SIZE = { width: 0.22, height: 0.32, frame: 0.03 };
const WINDOW_GEOMETRIES = {
  glass: new THREE.PlaneGeometry(WINDOW_SIZE.width, WINDOW_SIZE.height),
  glow: new THREE.PlaneGeometry(WINDOW_SIZE.width - 0.02, WINDOW_SIZE.height - 0.02),
  top: new THREE.BoxGeometry(WINDOW_SIZE.width + WINDOW_SIZE.frame * 2, WINDOW_SIZE.frame, 0.02),
  side: new THREE.BoxGeometry(WINDOW_SIZE.frame, WINDOW_SIZE.height, 0.02),
  crossV: new THREE.BoxGeometry(0.015, WINDOW_SIZE.height, 0.015),
  crossH: new THREE.BoxGeometry(WINDOW_SIZE.width, 0.015, 0.015),
  sill: new THREE.BoxGeometry(WINDOW_SIZE.width + WINDOW_SIZE.frame * 2 + 0.04, 0.025, 0.04),
};

function addWindow(group, x, y, z, rotY) {
  const winGroup = new THREE.Group();
  winGroup.position.set(x, y, z);
  winGroup.rotation.y = rotY;

  const glass = new THREE.Mesh(WINDOW_GEOMETRIES.glass, WINDOW_GLASS_MAT);
  glass.position.z = 0.001;
  winGroup.add(glass);

  const glow = new THREE.Mesh(WINDOW_GEOMETRIES.glow, WINDOW_GLOW_MAT);
  glow.position.z = 0.0005;
  winGroup.add(glow);

  const top = new THREE.Mesh(WINDOW_GEOMETRIES.top, WINDOW_FRAME_MAT);
  top.position.set(0, WINDOW_SIZE.height / 2 + WINDOW_SIZE.frame / 2, 0.005);
  winGroup.add(top);

  const bot = new THREE.Mesh(WINDOW_GEOMETRIES.top, WINDOW_FRAME_MAT);
  bot.position.set(0, -WINDOW_SIZE.height / 2 - WINDOW_SIZE.frame / 2, 0.005);
  winGroup.add(bot);

  const left = new THREE.Mesh(WINDOW_GEOMETRIES.side, WINDOW_FRAME_MAT);
  left.position.set(-WINDOW_SIZE.width / 2 - WINDOW_SIZE.frame / 2, 0, 0.005);
  winGroup.add(left);

  const right = new THREE.Mesh(WINDOW_GEOMETRIES.side, WINDOW_FRAME_MAT);
  right.position.set(WINDOW_SIZE.width / 2 + WINDOW_SIZE.frame / 2, 0, 0.005);
  winGroup.add(right);

  const crossV = new THREE.Mesh(WINDOW_GEOMETRIES.crossV, WINDOW_FRAME_MAT);
  crossV.position.z = 0.005;
  winGroup.add(crossV);

  const crossH = new THREE.Mesh(WINDOW_GEOMETRIES.crossH, WINDOW_FRAME_MAT);
  crossH.position.set(0, 0.02, 0.005);
  winGroup.add(crossH);

  const sill = new THREE.Mesh(WINDOW_GEOMETRIES.sill, WINDOW_SILL_MAT);
  sill.position.set(0, -WINDOW_SIZE.height / 2 - WINDOW_SIZE.frame, 0.015);
  winGroup.add(sill);

  group.add(winGroup);
}

function addGableRoof(group, cx, cz, bw, bd, h, roofCol) {
  const roofMat = new THREE.MeshLambertMaterial({ color: roofCol, transparent: true, side: THREE.DoubleSide });
  const overhang = 0.15;
  const ridgeAlongX = bw >= bd;
  const spanW = ridgeAlongX ? bd : bw;
  const spanL = ridgeAlongX ? bw : bd;
  const roofH = 0.4 + spanW * 0.15;
  const hw = spanW / 2 + overhang;
  const hl = spanL / 2 + overhang;
  const vertices = [];
  const indices = [];

  if (ridgeAlongX) {
    vertices.push(
      cx - hl, h, cz - hw,
      cx - hl, h, cz + hw,
      cx - hl, h + roofH, cz,
      cx + hl, h, cz - hw,
      cx + hl, h, cz + hw,
      cx + hl, h + roofH, cz
    );
  } else {
    vertices.push(
      cx - hw, h, cz - hl,
      cx + hw, h, cz - hl,
      cx, h + roofH, cz - hl,
      cx - hw, h, cz + hl,
      cx + hw, h, cz + hl,
      cx, h + roofH, cz + hl
    );
  }

  indices.push(0, 3, 5, 0, 5, 2);
  indices.push(1, 2, 5, 1, 5, 4);
  indices.push(0, 2, 1);
  indices.push(3, 4, 5);

  const roofGeo = new THREE.BufferGeometry();
  roofGeo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
  roofGeo.setIndex(indices);
  roofGeo.computeVertexNormals();

  const roof = new THREE.Mesh(roofGeo, roofMat);
  roof.castShadow = true;
  roof.receiveShadow = true;
  group.add(roof);

  const ridgeGeo = new THREE.BoxGeometry(
    ridgeAlongX ? spanL + overhang * 2 : 0.06,
    0.04,
    ridgeAlongX ? 0.06 : spanL + overhang * 2
  );
  const ridge = new THREE.Mesh(ridgeGeo, new THREE.MeshLambertMaterial({ color: 0x444440, transparent: true }));
  ridge.position.set(cx, h + roofH, cz);
  group.add(ridge);
}

for (let i = 0; i < gInfo.length; i++) {
  const g = gInfo[i];
  const pal = g.pal;
  const h = g.h;
  const bw = g.w;
  const bd = g.d;
  const floors = g.floors;
  const floorH = g.floorH;
  const cx = worldXFromCol((g.minC + g.maxC) / 2);
  const cz = worldZFromRow((g.minR + g.maxR) / 2);
  const bldGroup = new THREE.Group();

  const topMat = new THREE.MeshLambertMaterial({ color: pal.t, transparent: true });
  const leftMat = new THREE.MeshLambertMaterial({ color: pal.l, transparent: true });
  const rightMat = new THREE.MeshLambertMaterial({ color: pal.r, transparent: true });
  const mats = [rightMat, leftMat, topMat, topMat, rightMat, leftMat];

  const bld = new THREE.Mesh(new THREE.BoxGeometry(bw - 0.05, h, bd - 0.05), mats);
  bld.position.set(cx, h / 2, cz);
  bld.castShadow = true;
  bld.receiveShadow = true;
  bldGroup.add(bld);

  if (floors === 2) {
    const sepMat = new THREE.MeshLambertMaterial({ color: pal.l, transparent: true });
    for (const side of [-1, 1]) {
      const sep = new THREE.Mesh(new THREE.BoxGeometry(0.02, 0.05, bd - 0.03), sepMat);
      sep.position.set(cx + side * (bw / 2 - 0.01), floorH, cz);
      bldGroup.add(sep);
    }
    for (const side of [-1, 1]) {
      const sep = new THREE.Mesh(new THREE.BoxGeometry(bw - 0.03, 0.05, 0.02), sepMat);
      sep.position.set(cx, floorH, cz + side * (bd / 2 - 0.01));
      bldGroup.add(sep);
    }
  }

  const roofCol = ROOF_COLORS[i % ROOF_COLORS.length];
  if (g.roofType === 1) {
    addGableRoof(bldGroup, cx, cz, bw, bd, h, roofCol);
  } else {
    const roofMat = new THREE.MeshLambertMaterial({ color: roofCol, transparent: true });
    const parMat = new THREE.MeshLambertMaterial({ color: 0x888880, transparent: true });
    const slab = new THREE.Mesh(new THREE.BoxGeometry(bw + 0.08, 0.06, bd + 0.08), roofMat);
    slab.position.set(cx, h + 0.03, cz);
    slab.castShadow = true;
    bldGroup.add(slab);

    const parH = 0.12;
    const parW = 0.06;
    const parFB = new THREE.BoxGeometry(bw + 0.08, parH, parW);
    const parLR = new THREE.BoxGeometry(parW, parH, bd + 0.08);
    for (const side of [-1, 1]) {
      const pf = new THREE.Mesh(parFB, parMat);
      pf.position.set(cx, h + 0.06 + parH / 2, cz + side * (bd / 2 + 0.04 - parW / 2));
      bldGroup.add(pf);

      const pl = new THREE.Mesh(parLR, parMat);
      pl.position.set(cx + side * (bw / 2 + 0.04 - parW / 2), h + 0.06 + parH / 2, cz);
      bldGroup.add(pl);
    }
  }

  for (let f = 0; f < floors; f++) {
    const winY = f * floorH + floorH * 0.55;
    const winCountZ = Math.max(1, Math.floor(bd / 1.2));
    const winSpacingZ = bd / (winCountZ + 1);

    for (let wi = 1; wi <= winCountZ; wi++) {
      const wz = worldZFromRow(g.minR) + wi * winSpacingZ - 0.5;
      for (const side of [-1, 1]) {
        addWindow(bldGroup, cx + side * (bw / 2), winY, wz, side > 0 ? Math.PI / 2 : -Math.PI / 2);
      }
    }

    const winCountX = Math.max(1, Math.floor(bw / 1.2));
    const winSpacingX = bw / (winCountX + 1);
    for (let wi = 1; wi <= winCountX; wi++) {
      const wx = worldXFromCol(g.minC) + wi * winSpacingX - 0.5;
      for (const side of [-1, 1]) {
        if (f === 0 && side === 1 && Math.abs(wx - cx) < 0.35) continue;
        addWindow(bldGroup, wx, winY, cz + side * (bd / 2), side > 0 ? 0 : Math.PI);
      }
    }
  }

  const doorH = Math.min(0.8, floorH * 0.6);
  const doorMat = new THREE.MeshLambertMaterial({ color: 0x3A2815, transparent: true });
  const door = new THREE.Mesh(new THREE.PlaneGeometry(0.35, doorH), doorMat);
  door.position.set(cx, doorH / 2, cz + bd / 2 + 0.001);
  bldGroup.add(door);

  const dfMat = new THREE.MeshLambertMaterial({ color: 0x2A1A10, transparent: true });
  const dfTop = new THREE.Mesh(new THREE.BoxGeometry(0.42, 0.035, 0.02), dfMat);
  dfTop.position.set(cx, doorH + 0.015, cz + bd / 2 + 0.005);
  bldGroup.add(dfTop);

  for (const side of [-1, 1]) {
    const dfSide = new THREE.Mesh(new THREE.BoxGeometry(0.03, doorH - 0.05, 0.02), dfMat);
    dfSide.position.set(cx + side * 0.19, (doorH - 0.05) / 2 + 0.05, cz + bd / 2 + 0.005);
    bldGroup.add(dfSide);
  }

  const foundMat = new THREE.MeshLambertMaterial({ color: 0x666660, transparent: true });
  const found = new THREE.Mesh(new THREE.BoxGeometry(bw + 0.02, 0.1, bd + 0.02), foundMat);
  found.position.set(cx, 0.05, cz);
  bldGroup.add(found);

  scene.add(bldGroup);
  registerOccludable(bldGroup);
}

/* ── Fences and gates (type 6, 7) ── */
const fenceMat = new THREE.MeshLambertMaterial({ color: 0x8B7355, transparent: true });
const fencePostGeo = new THREE.BoxGeometry(0.06, 0.6, 0.06);
const fenceRailGeo = new THREE.BoxGeometry(0.04, 0.04, 1);
const fenceRailGeoX = new THREE.BoxGeometry(1, 0.04, 0.04);
const wicketMat = new THREE.MeshLambertMaterial({ color: 0x6B5B45, transparent: true });
const wicketFrameMat = new THREE.MeshLambertMaterial({ color: 0x5A4A35, transparent: true });
const wicketBraceGeo = new THREE.BoxGeometry(0.04, 0.04, 0.78);
const wicketPostGeo = new THREE.BoxGeometry(0.05, 0.52, 0.05);
const wicketRailGeoX = new THREE.BoxGeometry(0.84, 0.04, 0.04);
const wicketRailGeoZ = new THREE.BoxGeometry(0.04, 0.04, 0.84);
const FENCE_COLLIDER_HALF_THICKNESS = 0.09;
const FENCE_POST_COLLIDER_HALF_SIZE = 0.08;

function addFencePost(group, x, z, height, material, geo = fencePostGeo) {
  const post = new THREE.Mesh(geo, material);
  post.position.set(x, height / 2, z);
  post.castShadow = true;
  group.add(post);
}

function addHorizontalFenceCollision(c, r) {
  addFenceCollider(c + 0.5, r, 0.5, FENCE_COLLIDER_HALF_THICKNESS);
}

function addVerticalFenceCollision(c, r) {
  addFenceCollider(c, r + 0.5, FENCE_COLLIDER_HALF_THICKNESS, 0.5);
}

function addFencePostCollision(c, r) {
  addFenceCollider(c, r, FENCE_POST_COLLIDER_HALF_SIZE, FENCE_POST_COLLIDER_HALF_SIZE);
}

function addHorizontalGate(group, fx, fz) {
  const postOffset = 0.46;

  addFencePost(group, fx - postOffset, fz, 0.52, wicketFrameMat, wicketPostGeo);
  addFencePost(group, fx + postOffset, fz, 0.52, wicketFrameMat, wicketPostGeo);

  for (const y of [0.18, 0.35]) {
    const rail = new THREE.Mesh(wicketRailGeoX, wicketMat);
    rail.position.set(fx, y, fz);
    group.add(rail);
  }

  const brace = new THREE.Mesh(wicketBraceGeo, wicketFrameMat);
  brace.position.set(fx, 0.265, fz);
  brace.rotation.x = Math.PI / 4;
  brace.rotation.y = Math.PI / 2;
  group.add(brace);
}

function addVerticalGate(group, fx, fz) {
  const postOffset = 0.46;

  addFencePost(group, fx, fz - postOffset, 0.52, wicketFrameMat, wicketPostGeo);
  addFencePost(group, fx, fz + postOffset, 0.52, wicketFrameMat, wicketPostGeo);

  for (const y of [0.18, 0.35]) {
    const rail = new THREE.Mesh(wicketRailGeoZ, wicketMat);
    rail.position.set(fx, y, fz);
    group.add(rail);
  }

  const brace = new THREE.Mesh(wicketBraceGeo, wicketFrameMat);
  brace.position.set(fx, 0.265, fz);
  brace.rotation.z = Math.PI / 4;
  group.add(brace);
}

for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  const t = MAP[r][c];
  if (!isFenceTile(t)) continue;

  const fx = worldXFromCol(c);
  const fz = worldZFromRow(r);
  const fGroup = new THREE.Group();
  const hasRightNeighbor = c + 1 < MW && isFenceTile(MAP[r][c + 1]);
  const hasBottomNeighbor = r + 1 < MH && isFenceTile(MAP[r + 1][c]);

  addFencePostCollision(c, r);

  if (t === BUILDING_TILE.fence) {
    addFencePost(fGroup, fx, fz, 0.6, fenceMat);

    if (hasRightNeighbor) {
      const railTop = new THREE.Mesh(fenceRailGeoX, fenceMat);
      railTop.position.set(fx + 0.5, 0.5, fz);
      fGroup.add(railTop);

      const railBot = new THREE.Mesh(fenceRailGeoX, fenceMat);
      railBot.position.set(fx + 0.5, 0.2, fz);
      fGroup.add(railBot);
      addHorizontalFenceCollision(c, r);
    }

    if (hasBottomNeighbor) {
      const railTop = new THREE.Mesh(fenceRailGeo, fenceMat);
      railTop.position.set(fx, 0.5, fz + 0.5);
      fGroup.add(railTop);

      const railBot = new THREE.Mesh(fenceRailGeo, fenceMat);
      railBot.position.set(fx, 0.2, fz + 0.5);
      fGroup.add(railBot);
      addVerticalFenceCollision(c, r);
    }
  } else {
    if (hasRightNeighbor && !hasBottomNeighbor) {
      addHorizontalGate(fGroup, fx + 0.5, fz);
      addHorizontalFenceCollision(c, r);
    } else if (hasBottomNeighbor && !hasRightNeighbor) {
      addVerticalGate(fGroup, fx, fz + 0.5);
      addVerticalFenceCollision(c, r);
    } else {
      addFencePost(fGroup, fx, fz, 0.52, wicketFrameMat, wicketPostGeo);
    }
  }

  scene.add(fGroup);
  registerOccludable(fGroup);
}

/* ── Small structures (type 3) ── */
for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  if (MAP[r][c] !== BUILDING_TILE.structure) continue;

  const sx = worldXFromCol(c);
  const sz = worldZFromRow(r);
  const sh = 0.35 + ((c * 7 + r * 3) % 5) * 0.06;
  const col = SMALL_STRUCTURE_COLORS[(c * 7 + r * 3) % SMALL_STRUCTURE_COLORS.length];
  const sGroup = new THREE.Group();
  const sMat = new THREE.MeshLambertMaterial({ color: col, transparent: true });
  const sMesh = new THREE.Mesh(new THREE.BoxGeometry(0.45, sh, 0.45), sMat);
  sMesh.position.set(sx, sh / 2, sz);
  sMesh.castShadow = true;
  sMesh.receiveShadow = true;
  sGroup.add(sMesh);
  scene.add(sGroup);
  registerOccludable(sGroup);
}


/* ── Trees ── */
/* Scale: 1 unit ≈ 2.5m, trees ~8-12m = ~3.5-5 units */

const trunkGeo = new THREE.CylinderGeometry(0.1, 0.15, 2.5, 6);
const trunkMat = new THREE.MeshLambertMaterial({ color: 0x5C3A1E, transparent: true });
const foliageLayers = [
  { y: 2.0, r: 1.1, color: 0x1A5C0A },
  { y: 2.5, r: 0.95, color: 0x236614 },
  { y: 3.0, r: 0.8, color: 0x2C7420 },
  { y: 3.5, r: 0.6, color: 0x358228 },
  { y: 3.9, r: 0.35, color: 0x3E9030 },
];
const foliageMeshes = foliageLayers.map(layer => ({
  y: layer.y,
  geometry: new THREE.SphereGeometry(layer.r, 8, 6),
  material: new THREE.MeshLambertMaterial({ color: layer.color, transparent: true }),
}));

for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  if (MAP[r][c] !== WORLD.tiles.tree) continue;

  const tx = worldXFromCol(c);
  const tz = worldZFromRow(r);
  const treeGroup = new THREE.Group();

  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.position.set(tx, 1.25, tz);
  trunk.castShadow = true;
  treeGroup.add(trunk);

  for (const layer of foliageMeshes) {
    const foliage = new THREE.Mesh(layer.geometry, layer.material);
    foliage.position.set(tx, layer.y, tz);
    foliage.castShadow = true;
    treeGroup.add(foliage);
  }

  scene.add(treeGroup);
  registerOccludable(treeGroup);
}


/* ── Player Mesh ── */
