// Face
const eyeMat = new THREE.MeshBasicMaterial({ color: 0x2A2015 });
const eyeL = new THREE.Mesh(new THREE.BoxGeometry(0.035, 0.025, 0.01), eyeMat);
eyeL.position.set(-0.045, 0.01, 0.12);
headGroup.add(eyeL);
const eyeR = new THREE.Mesh(new THREE.BoxGeometry(0.035, 0.025, 0.01), eyeMat);
eyeR.position.set(0.045, 0.01, 0.12);
headGroup.add(eyeR);

const nose = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.03, 0.02), new THREE.MeshLambertMaterial({ color: 0xB8896A }));
nose.position.set(0, -0.02, 0.125);
headGroup.add(nose);

const mouth = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.01, 0.01), new THREE.MeshBasicMaterial({ color: 0x8A5A4A }));
mouth.position.set(0, -0.055, 0.12);
headGroup.add(mouth);

const earMat = new THREE.MeshLambertMaterial({ color: 0xB88A60 });
const earL = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.06, 0.05), earMat);
earL.position.set(-0.125, 0, 0);
headGroup.add(earL);
const earR = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.06, 0.05), earMat);
earR.position.set(0.125, 0, 0);
headGroup.add(earR);

// ── Left leg pivot (at hip) ──
const legPivotL = new THREE.Group();
legPivotL.position.set(-0.08, 0.46, 0);
playerGroup.add(legPivotL);

const legGeo = new THREE.BoxGeometry(0.13, 0.38, 0.14);
const legMat = new THREE.MeshLambertMaterial({ color: 0x3A4A5C });
const legL = new THREE.Mesh(legGeo, legMat);
legL.position.y = -0.19;
legL.castShadow = true;
legPivotL.add(legL);

const shoeGeo = new THREE.BoxGeometry(0.13, 0.08, 0.2);
const shoeMat = new THREE.MeshLambertMaterial({ color: 0x2A2018 });
const shoeL = new THREE.Mesh(shoeGeo, shoeMat);
shoeL.position.set(0, -0.4, 0.02);
shoeL.castShadow = true;
legPivotL.add(shoeL);

// ── Right leg pivot (at hip) ──
const legPivotR = new THREE.Group();
legPivotR.position.set(0.08, 0.46, 0);
playerGroup.add(legPivotR);

const legR = new THREE.Mesh(legGeo, legMat);
legR.position.y = -0.19;
legR.castShadow = true;
legPivotR.add(legR);

const shoeR = new THREE.Mesh(shoeGeo, shoeMat);
shoeR.position.set(0, -0.4, 0.02);
shoeR.castShadow = true;
legPivotR.add(shoeR);

// ── Shadow blob ──
const shadowGeo = new THREE.CircleGeometry(0.18, 12);
const shadowMeshMat = new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.25 });
const shadowMesh = new THREE.Mesh(shadowGeo, shadowMeshMat);
shadowMesh.rotation.x = -Math.PI / 2;
shadowMesh.position.y = 0.01;
playerGroup.add(shadowMesh);

// Apply scale
playerGroup.scale.set(playerScale, playerScale, playerScale);
scene.add(playerGroup);


/* ── Player Movement & Animation ── */

const MOVE_CFG = CONFIG.player.movement;
const ANIM_CFG = CONFIG.player.animation;
const WALK_SPEED = MOVE_CFG.walkSpeed;
const RUN_SPEED = MOVE_CFG.runSpeed;
const ACCEL = MOVE_CFG.accel;
const DECEL = MOVE_CFG.decel;

const pl = {
  x: CONFIG.player.spawn.x, y: CONFIG.player.spawn.y, angle: 0,
  walkTime: 0, speed: 0, targetSpeed: 0,
  moving: false, running: false
};

const ANIM = {
  walk: ANIM_CFG.walk,
  run: ANIM_CFG.run
};

function updatePlayerPos() {
  playerGroup.position.set(pl.x - MW / 2 + 0.5, 0, pl.y - MH / 2 + 0.5);
  playerGroup.rotation.y = pl.angle;
}
updatePlayerPos();

function lerpTo(current, target, rate, dt) {
  return current + (target - current) * Math.min(1, rate * dt);
}

function update(dt) {
  let dx = 0, dz = 0;
  if (keys['ArrowLeft']  || keys['KeyA']) { dx--; dz++; }
  if (keys['ArrowRight'] || keys['KeyD']) { dx++; dz--; }
  if (keys['ArrowUp']    || keys['KeyW']) { dx--; dz--; }
  if (keys['ArrowDown']  || keys['KeyS']) { dx++; dz++; }

  pl.running = !!(keys['ShiftLeft'] || keys['ShiftRight']);
  pl.moving = dx !== 0 || dz !== 0;

  // ── Speed with acceleration/deceleration ──
  if (pl.moving) {
    pl.targetSpeed = pl.running ? RUN_SPEED : WALK_SPEED;
    pl.speed = lerpTo(pl.speed, pl.targetSpeed, ACCEL, dt);
  } else {
    pl.speed = lerpTo(pl.speed, 0, DECEL, dt);
    if (pl.speed < MOVE_CFG.minSpeed) pl.speed = 0;
  }

  // ── Movement ──
  if (pl.moving) {
    const len = Math.sqrt(dx * dx + dz * dz);
    dx = dx / len * pl.speed * dt;
    dz = dz / len * pl.speed * dt;

    const nx = pl.x + dx, ny = pl.y + dz;
    if (!isSolid(nx, pl.y)) pl.x = Math.max(0.5, Math.min(MW - 1.5, nx));
    if (!isSolid(pl.x, ny)) pl.y = Math.max(0.5, Math.min(MH - 1.5, ny));

    // Rotate toward movement direction
    const targetAngle = Math.atan2(dx, dz);
    let diff = targetAngle - pl.angle;
    while (diff > Math.PI) diff -= Math.PI * 2;
    while (diff < -Math.PI) diff += Math.PI * 2;
    pl.angle += diff * Math.min(1, MOVE_CFG.turnSpeed * dt);
  }

  const isRunAnim = pl.speed > WALK_SPEED * ANIM_CFG.runThreshold;
  const a = isRunAnim ? ANIM.run : ANIM.walk;

  const intensity = Math.min(1, pl.speed / WALK_SPEED);

  if (pl.speed > MOVE_CFG.minSpeed) {
    pl.walkTime += dt * a.freq * (pl.speed / (isRunAnim ? RUN_SPEED : WALK_SPEED));
  }

  const phase = pl.walkTime;
  const sinP = Math.sin(phase);

  const legSwing = sinP * a.legAmp * intensity;
  legPivotL.rotation.x = legSwing;
  legPivotR.rotation.x = -legSwing;

  const armSwing = sinP * a.armAmp * intensity;
  armPivotL.rotation.x = -armSwing;
  armPivotR.rotation.x = armSwing;

  upperBody.position.y = ANIM_CFG.upperBodyY;
  headGroup.position.y = ANIM_CFG.headY;

  const leanTarget = isRunAnim ? a.leanFwd * intensity : 0;
  upperBody.rotation.x = lerpTo(upperBody.rotation.x, leanTarget, ANIM_CFG.bodyReturnRate, dt);

  if (pl.speed < MOVE_CFG.minSpeed) {
    legPivotL.rotation.x = lerpTo(legPivotL.rotation.x, 0, ANIM_CFG.idleReturnRate, dt);
    legPivotR.rotation.x = lerpTo(legPivotR.rotation.x, 0, ANIM_CFG.idleReturnRate, dt);
    armPivotL.rotation.x = lerpTo(armPivotL.rotation.x, 0, ANIM_CFG.idleReturnRate, dt);
    armPivotR.rotation.x = lerpTo(armPivotR.rotation.x, 0, ANIM_CFG.idleReturnRate, dt);
    upperBody.rotation.x = lerpTo(upperBody.rotation.x, 0, ANIM_CFG.bodyReturnRate, dt);
  }

  updatePlayerPos();
}


/* ── Camera ── */

const camOffset = new THREE.Vector3(...CONFIG.camera.offset);
const lightOffset = new THREE.Vector3(...CONFIG.camera.lightOffset);
const camTarget = new THREE.Vector3();
const occPlayerPos = new THREE.Vector3();
const occDir = new THREE.Vector3();
const occNowBlocking = new Set();

function updateCamera() {
  camTarget.copy(playerGroup.position);
  cam.position.copy(camTarget).add(camOffset);
  cam.lookAt(camTarget);
  cam.updateProjectionMatrix();
  dirLight.position.copy(camTarget).add(lightOffset);
  dirLight.target.position.copy(camTarget);
  dirLight.target.updateMatrixWorld();

  updateOcclusion();
}

/* ── Zoom ── */

const ZOOM_MIN = CONFIG.camera.zoom.min;
const ZOOM_MAX = CONFIG.camera.zoom.max;
renderer.domElement.addEventListener('wheel', e => {
  e.preventDefault();
  cam.zoom *= e.deltaY > 0 ? CONFIG.camera.zoom.wheelStepOut : CONFIG.camera.zoom.wheelStepIn;
  cam.zoom = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, cam.zoom));
  cam.updateProjectionMatrix();
}, { passive: false });

/* ── Occlusion (PZ-style see-through) ── */

const occRaycaster = new THREE.Raycaster();
const occFadeSpeed = CONFIG.occlusion.fadeSpeed;
const occTargetAlpha = CONFIG.occlusion.targetAlpha;
let occFaded = new Set();

function setGroupOpacity(group, alpha) {
  for (const child of group.userData.occlusionMeshes || []) {
    if (!child.material) continue;
    const mats = Array.isArray(child.material) ? child.material : [child.material];
    for (const mat of mats) {
      mat.opacity = alpha;
      mat.depthWrite = alpha > 0.9;
    }
  }
}

function updateOcclusion() {
  occPlayerPos.copy(playerGroup.position);
  occPlayerPos.y += CONFIG.occlusion.playerHeightOffset;

  occDir.copy(occPlayerPos).sub(cam.position).normalize();
  const dist = cam.position.distanceTo(occPlayerPos);
  occRaycaster.set(cam.position, occDir);
  occRaycaster.far = dist;

  const hits = occRaycaster.intersectObjects(GAME.occlusionMeshes, false);

  occNowBlocking.clear();
  for (const hit of hits) {
    const group = hit.object.userData.occludableGroup;
    if (group) occNowBlocking.add(group);
  }

  for (const group of occFaded) {
    if (!occNowBlocking.has(group)) {
      group.userData.occAlpha = Math.min(1, (group.userData.occAlpha || 0.2) + occFadeSpeed * 0.016);
      setGroupOpacity(group, group.userData.occAlpha);
      if (group.userData.occAlpha >= 1) {
        setGroupOpacity(group, 1);
        occFaded.delete(group);
        delete group.userData.occAlpha;
      }
    }
  }

  for (const group of occNowBlocking) {
    occFaded.add(group);
    group.userData.occAlpha = Math.max(occTargetAlpha, (group.userData.occAlpha || 1) - occFadeSpeed * 0.016);
    setGroupOpacity(group, group.userData.occAlpha);
  }
}


/* ── HUD & Fullscreen ── */

const hud = document.getElementById('hud');
const btnFs = document.getElementById('btn-fs');
const wrap = document.getElementById('wrap');

btnFs.addEventListener('click', () => {
  if (!document.fullscreenElement) {
    (wrap.requestFullscreen || wrap.webkitRequestFullscreen || wrap.mozRequestFullScreen).call(wrap);
  } else {
    (document.exitFullscreen || document.webkitExitFullscreen || document.mozCancelFullScreen).call(document);
  }
});

document.addEventListener('fullscreenchange', () => {
  btnFs.textContent = document.fullscreenElement ? '✕ Exit' : '⛶ Fullscreen';
  setTimeout(onResize, 100);
});

function updateHud() {
  hud.textContent = `pos: ${pl.x.toFixed(1)}, ${pl.y.toFixed(1)}  zoom: ${cam.zoom.toFixed(2)}x`;
}


/* ── Resize ── */

function onResize() {
  const w = window.innerWidth, h = window.innerHeight;
  aspect = w / h;
  cam.left = -frustum * aspect;
  cam.right = frustum * aspect;
  cam.top = frustum;
  cam.bottom = -frustum;
  cam.updateProjectionMatrix();
  renderer.setSize(w, h);
}
window.addEventListener('resize', onResize);

/* ── Loading Screen ── */

const loaderEl = document.getElementById('loader');
const loaderBtn = document.getElementById('loader-play');
const loaderText = document.querySelector('.loader-text');
const loaderFill = document.querySelector('.loader-fill');
const loaderName = document.querySelector('.loader-name');
const playerNameInput = document.getElementById('player-name');
const bootstrap = window.ISOMANIA_BOOTSTRAP || {};
let playerName = localStorage.getItem(CONFIG.ui.playerNameStorageKey) || '';

function notifyGameJoin(name) {
  if (!bootstrap.notifyUrl || !bootstrap.gameToken) return;

  fetch(bootstrap.notifyUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Game-Token': bootstrap.gameToken,
    },
    body: JSON.stringify({ name }),
    keepalive: true,
  }).catch(() => {
    // Notification failures should not block game start.
  });
}

function showPlayButton() {
  loaderText.style.display = 'none';
  loaderFill.style.animation = 'none';
  loaderFill.style.width = '100%';
  loaderFill.style.marginLeft = '0';
  loaderName.style.display = 'block';
  loaderBtn.style.display = 'block';
  if (playerName) {
    playerNameInput.value = playerName;
    loaderBtn.disabled = false;
  } else {
    loaderBtn.disabled = true;
    loaderBtn.classList.add('disabled');
  }
  playerNameInput.focus();
}

// Enable play button only when name is entered
playerNameInput.addEventListener('input', () => {
  const hasName = playerNameInput.value.trim().length > 0;
  loaderBtn.disabled = !hasName;
  loaderBtn.classList.toggle('disabled', !hasName);
});

function hideLoader() {
  loaderEl.style.opacity = '0';
  setTimeout(() => { loaderEl.style.display = 'none'; }, 400);
}

/* ── Game Loop ── */

let prev = performance.now();
let gameStarted = false;

function loop(ts) {
  const dt = Math.min((ts - prev) / 1000, 0.05);
  prev = ts;
  if (gameStarted) {
    update(dt);
  }
  updateCamera();
  renderer.render(scene, cam);
  updateHud();
  requestAnimationFrame(loop);
}

// Scene is ready — show play button
showPlayButton();

// Render scene in background while waiting
requestAnimationFrame(loop);

// Start game on click
loaderBtn.addEventListener('click', () => {
  if (!playerNameInput.value.trim()) return;
  playerName = playerNameInput.value.trim();
  localStorage.setItem(CONFIG.ui.playerNameStorageKey, playerName);
  notifyGameJoin(playerName);
  clearKeys();
  gameStarted = true;
  prev = performance.now();
  hideLoader();
});

// Enter key in name input triggers play
playerNameInput.addEventListener('keydown', e => {
  if (e.key === 'Enter' && playerNameInput.value.trim()) {
    loaderBtn.click();
  }
});


